Enable Dynamic Token Ring and Turn Marke.command:
const setting = game.settings.get("core", foundry.documents.Combat.CONFIG_SETTING);
foundry.utils.mergeObject(setting, { turnMarker: {
  src: "modules/sf2e-murder-in-metal-city/assets/ring/murder-in-metal-city-turn-marker.webp",
  enabled: true,
  animation: "pulse", // options: "" / "spin" / "spinPulse" / "pulse"
} });
await game.settings.set("core", foundry.documents.Combat.CONFIG_SETTING, setting);

game.settings.set("core", "dynamicTokenRing", "sf2e-murder-in-metal-city");
foundry.applications.settings.SettingsConfig.reloadConfirm();
